"use client";

import { useState } from "react";
import { SectionWrapper } from "@/components/ui/SectionWrapper";
import { Card } from "@/components/ui/Card";
import { Button } from "@/components/ui/Button";
import { Check, Plus, Minus } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

const plans = [
  {
    name: "Starter",
    priceMonthly: "$2,500",
    priceYearly: "$25,000",
    description: "Perfect for small businesses.",
    features: ["Custom Design", "5 Pages", "Responsive", "SEO Basic"],
  },
  {
    name: "Growth",
    priceMonthly: "$5,000",
    priceYearly: "$50,000",
    description: "Best for growing brands.",
    popular: true,
    features: ["Custom Design", "10 Pages", "Advanced SEO", "CMS Integration", "Analytics"],
  },
  {
    name: "Enterprise",
    priceMonthly: "Custom",
    priceYearly: "Custom",
    description: "For large scale applications.",
    features: ["Full Custom Solution", "Unlimited Pages", "Priority Support", "Custom Integrations"],
  },
];

const faqs = [
  { question: "How long does a project take?", answer: "Typically 4-8 weeks depending on complexity." },
  { question: "Do you offer maintenance?", answer: "Yes, we have ongoing support packages available." },
  { question: "What is your payment structure?", answer: "50% upfront, 50% upon completion." },
];

export function PricingFAQ() {
  const [openFaq, setOpenFaq] = useState<number | null>(null);
  const [isYearly, setIsYearly] = useState(false);

  return (
    <SectionWrapper>
      <div className="mb-24 text-center">
         <h2 className="text-5xl md:text-7xl font-heading font-bold uppercase mb-6">Invest in Growth</h2>
      </div>

      <div className="flex justify-center mb-12">
        <div className="inline-flex items-center rounded-full border border-white/10 bg-white/5 p-1">
          <button
            onClick={() => setIsYearly(false)}
            className={`px-5 py-2 rounded-full text-sm ${!isYearly ? "bg-accent text-white" : "text-white/70"}`}
          >
            Monthly
          </button>
          <button
            onClick={() => setIsYearly(true)}
            className={`px-5 py-2 rounded-full text-sm ${isYearly ? "bg-accent text-white" : "text-white/70"}`}
          >
            Yearly
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-32">
        {plans.map((plan, index) => (
          <Card key={index} className={cn("relative flex flex-col p-8", plan.popular ? "border-accent bg-accent/5" : "")}>
            {plan.popular && (
               <span className="absolute top-0 right-0 bg-accent text-white text-xs font-bold px-3 py-1 rounded-bl-lg uppercase tracking-wider">Popular</span>
            )}
            <h3 className="text-2xl font-bold mb-2">{plan.name}</h3>
            <div className="text-4xl font-heading font-bold mb-1">
              {isYearly ? plan.priceYearly : plan.priceMonthly}
            </div>
            <div className="text-xs uppercase tracking-wider text-white/50 mb-4">
              {isYearly ? "Billed Yearly • Save ~15%" : "Billed Monthly"}
            </div>
            <p className="text-white/60 mb-8 text-sm">{plan.description}</p>
            
            <ul className="flex-1 space-y-4 mb-8">
               {plan.features.map((feature, i) => (
                  <li key={i} className="flex items-center text-sm text-white/80">
                     <Check className="w-4 h-4 text-accent mr-3" />
                     {feature}
                  </li>
               ))}
            </ul>
            
            <Button variant={plan.popular ? "primary" : "outline"} className="w-full">Choose Plan</Button>
          </Card>
        ))}
      </div>
      
      <div className="max-w-3xl mx-auto">
         <h3 className="text-3xl font-heading font-bold uppercase mb-12 text-center">FAQ</h3>
         <div className="space-y-4">
            {faqs.map((faq, index) => (
               <div key={index} className="border-b border-white/10">
                  <button 
                     onClick={() => setOpenFaq(openFaq === index ? null : index)}
                     className="w-full flex justify-between items-center py-6 text-left focus:outline-none"
                  >
                     <span className="text-lg font-medium">{faq.question}</span>
                     {openFaq === index ? <Minus className="w-5 h-5 text-accent" /> : <Plus className="w-5 h-5 text-white/40" />}
                  </button>
                  <AnimatePresence>
                     {openFaq === index && (
                        <motion.div
                           initial={{ height: 0, opacity: 0 }}
                           animate={{ height: "auto", opacity: 1 }}
                           exit={{ height: 0, opacity: 0 }}
                           transition={{ duration: 0.3 }}
                           className="overflow-hidden"
                        >
                           <p className="pb-6 text-white/60 leading-relaxed">{faq.answer}</p>
                        </motion.div>
                     )}
                  </AnimatePresence>
               </div>
            ))}
         </div>
      </div>
    </SectionWrapper>
  );
}
